#include <bits/stdc++.h>
using namespace std;

const int N=102;

int t,n,m,f[N],dist[N];

int father(int x){
    if(f[x]==x)
        return x; 
    int tmp=f[x];
    f[x]=father(f[x]);
    dist[x]+=dist[tmp];
    return f[x];
}

int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d%d",&n,&m);
        for(int i=1;i<=n+1;i++)
            f[i]=i,dist[i]=0;
        bool flag=true;
        while(m--){
            int x,y,z;
            scanf("%d%d%d",&x,&y,&z);
            y++;
            int fx=father(x),fy=father(y);
            if(fx!=fy){
                if(fx>fy)
                    f[fy]=fx,dist[fy]=dist[x]-dist[y]-z;
                else
                    f[fx]=fy,dist[fx]=z-dist[x]+dist[y];
            }
            else if(dist[x]-dist[y]!=z)
                flag=false;
        }
        if(flag)
            puts("true");
        else
            puts("false");
    }
    return 0;
}
